// harness 提供的是 div 容器;创建真实 input 并用 inline 模式立即显示日历
const mount = document.getElementById('date'); const input = document.createElement('input'); input.type = 'text'; input.setAttribute('aria-label', 'Choose date'); input.style.cssText = 'box-sizing:border-box;width:100%;max-width:307px;padding:8px 10px;margin-bottom:8px'; mount.appendChild(input);
const css = document.createElement('link'); css.rel='stylesheet'; css.href='https://cdn.jsdelivr.net/npm/flatpickr@4.6.13/dist/flatpickr.min.css'; document.head.appendChild(css);
const { default: flatpickr } = await import('https://cdn.jsdelivr.net/npm/flatpickr@4.6.13/+esm');
const fp = flatpickr(input, { inline:true, appendTo:mount, mode:data.mode ?? 'range', dateFormat:data.dateFormat ?? 'Y-m-d', minDate:data.minDate, maxDate:data.maxDate, enableTime:data.enableTime ?? false, defaultDate:data.defaultDate, onChange:(sel, str) => { /* 消费 AI 接选中结果 */ } });

